void maximizarSuperficie(int n, int presupuesto, vector<pair<int, int>> objetos) {
  // Inicializar variables
  int superficieMaxima = 0;
  // Función recursiva para explorar soluciones
  void backtrack(int index, int presupuestoActual, int superficieActual) {
    // Caso base: si se ha recorrido todos los objetos
    if (index == n) {
      // Actualizar superficie máxima si es necesario
      return;
    }
    // Opción 1: no incluir el objeto actual
    backtrack(index + 1, presupuestoActual, superficieActual);
    // Opción 2: incluir el objeto actual si el presupuesto lo permite
    if (presupuestoActual + objetos[index].first <= presupuesto) {
      backtrack(index + 1, presupuestoActual + objetos[index].first, superficieActual + objetos[index].second);
    }
  }
  // Llamar a la función recursiva
  backtrack(0, 0, 0);
  // Imprimir la superficie máxima encontrada
}
